// Noncompliant: Nested switch statements create confusion
func processMessage(msgType string, subType string, data interface{}) error {
    switch msgType {
    case "email":
        switch subType {
        case "welcome":
            return sendWelcomeEmail(data)
        case "notification":
            return sendNotificationEmail(data)
        case "alert":
            switch data.(type) {
            case string:
                return sendTextAlert(data.(string))
            case map[string]interface{}:
                return sendStructuredAlert(data.(map[string]interface{}))
            default:
                return errors.New("unsupported alert data type")
            }
        default:
            return errors.New("unknown email subtype")
        }
    case "sms":
        switch subType {
        case "urgent":
            return sendUrgentSMS(data)
        case "normal":
            return sendNormalSMS(data)
        default:
            return errors.New("unknown SMS subtype")
        }
    default:
        return errors.New("unknown message type")
    }
}

