// Compliant: Extract nested logic into separate functions
func processMessage(msgType string, subType string, data interface{}) error {
    switch msgType {
    case "email":
        return processEmailMessage(subType, data)
    case "sms":
        return processSMSMessage(subType, data)
    default:
        return errors.New("unknown message type")
    }
}

func processEmailMessage(subType string, data interface{}) error {
    switch subType {
    case "welcome":
        return sendWelcomeEmail(data)
    case "notification":
        return sendNotificationEmail(data)
    case "alert":
        return processEmailAlert(data)
    default:
        return errors.New("unknown email subtype")
    }
}

func processEmailAlert(data interface{}) error {
    switch data.(type) {
    case string:
        return sendTextAlert(data.(string))
    case map[string]interface{}:
        return sendStructuredAlert(data.(map[string]interface{}))
    default:
        return errors.New("unsupported alert data type")
    }
}

func processSMSMessage(subType string, data interface{}) error {
    switch subType {
    case "urgent":
        return sendUrgentSMS(data)
    case "normal":
        return sendNormalSMS(data)
    default:
        return errors.New("unknown SMS subtype")
    }
}
